previewCss:
.darma-loader-darma-custom-679 {
  color: var(--loader-color, #8b5cf6);
  --loader-secondary-color: var(--loader-secondary-color, #c4b5fd);
  --loader-bg: var(--loader-bg, #ffffff);
width: 45px;
aspect-ratio: .75;
--c: no-repeat linear-gradient(currentColor 0 0);
background:
var(--c) 0% 100%,
var(--c) 50% 100%,
var(--c) 100% 100%;
background-size: 20% 65%;
animation: darma-loader-darma-custom-679-l5 1s infinite linear;
}
@keyframes darma-loader-darma-custom-679-l5 {
20% {background-position: 0% 50% ,50% 100%,100% 100%}
40% {background-position: 0% 0% ,50% 50% ,100% 100%}
60% {background-position: 0% 100%,50% 0% ,100% 50% }
80% {background-position: 0% 100%,50% 100%,100% 0% }
}

